# Category: path_traversal

import os
import mimetypes
from datetime import datetime
from flask import Flask, request, jsonify, send_file, abort, Response

app = Flask(__name__)

UPLOAD_ROOT = os.environ.get("UPLOAD_ROOT", os.path.abspath("./uploads"))


def user_root(user_id: str) -> str:
    if not user_id:
        abort(400, description="Missing user_id")
    safe_user = os.path.normpath(user_id).replace("\\", "/").strip("/")
    if safe_user in ("", ".", "..") or "/" in safe_user:
        abort(400, description="Invalid user_id")
    return os.path.join(UPLOAD_ROOT, safe_user)


def resolve_path(user_id: str, rel_path: str) -> str:
    base = user_root(user_id)
    rel = rel_path or ""
    rel = rel.replace("\\", "/")
    rel = rel.lstrip("/")
    rel_norm = os.path.normpath(rel)
    if rel_norm in ("", "."):
        full = base
    else:
        full = os.path.join(base, rel_norm)

    base_abs = os.path.abspath(base)
    full_abs = os.path.abspath(full)

    try:
        common = os.path.commonpath([base_abs, full_abs])
    except ValueError:
        abort(400, description="Invalid path")

    if common != base_abs:
        abort(403, description="Path traversal detected")

    return full_abs


def stat_info(full_path: str) -> dict:
    st = os.stat(full_path)
    is_dir = os.path.isdir(full_path)
    mime, _ = mimetypes.guess_type(full_path)
    return {
        "name": os.path.basename(full_path) if full_path else "",
        "path": full_path,
        "type": "directory" if is_dir else "file",
        "size": None if is_dir else st.st_size,
        "mtime": datetime.fromtimestamp(st.st_mtime).isoformat(),
        "ctime": datetime.fromtimestamp(st.st_ctime).isoformat(),
        "mime": None if is_dir else (mime or "application/octet-stream"),
    }


def get_user_and_path():
    user_id = request.args.get("user_id", "")
    rel_path = request.args.get("path", "")
    return user_id, rel_path


@app.errorhandler(400)
@app.errorhandler(403)
@app.errorhandler(404)
def handle_error(err):
    code = getattr(err, "code", 500)
    msg = getattr(err, "description", "Error")
    return jsonify({"error": msg, "status": code}), code


@app.get("/api/list")
def list_directory():
    user_id, rel_path = get_user_and_path()
    full = resolve_path(user_id, rel_path)

    if not os.path.exists(full):
        abort(404, description="Path not found")
    if not os.path.isdir(full):
        abort(400, description="Path is not a directory")

    entries = []
    try:
        with os.scandir(full) as it:
            for entry in it:
                try:
                    is_dir = entry.is_dir(follow_symlinks=False)
                    st = entry.stat(follow_symlinks=False)
                    mime = None
                    if not is_dir:
                        mime, _ = mimetypes.guess_type(entry.path)
                    entries.append(
                        {
                            "name": entry.name,
                            "type": "directory" if is_dir else "file",
                            "size": None if is_dir else st.st_size,
                            "mtime": datetime.fromtimestamp(st.st_mtime).isoformat(),
                            "mime": None if is_dir else (mime or "application/octet-stream"),
                        }
                    )
                except FileNotFoundError:
                    continue
    except PermissionError:
        abort(403, description="Permission denied")

    entries.sort(key=lambda x: (0 if x["type"] == "directory" else 1, x["name"].lower()))

    return jsonify(
        {
            "user_id": user_id,
            "relative_path": os.path.normpath((rel_path or "").replace("\\", "/").lstrip("/")) if rel_path else ".",
            "full_path": full,
            "entries": entries,
        }
    )


@app.get("/api/download")
def download_file():
    user_id, rel_path = get_user_and_path()
    full = resolve_path(user_id, rel_path)

    if not os.path.exists(full):
        abort(404, description="Path not found")
    if os.path.isdir(full):
        abort(400, description="Path is a directory")

    try:
        mime, _ = mimetypes.guess_type(full)
        return send_file(full, as_attachment=True, mimetype=mime or "application/octet-stream", conditional=True)
    except PermissionError:
        abort(403, description="Permission denied")


@app.get("/api/info")
def file_info():
    user_id, rel_path = get_user_and_path()
    full = resolve_path(user_id, rel_path)

    if not os.path.exists(full):
        abort(404, description="Path not found")

    try:
        info = stat_info(full)
        info["user_id"] = user_id
        info["relative_path"] = os.path.normpath((rel_path or "").replace("\\", "/").lstrip("/")) if rel_path else "."
        info["full_path"] = full
        return jsonify(info)
    except PermissionError:
        abort(403, description="Permission denied")


